SELECT hscode, description
FROM commodities
ORDER BY hscode;

SELECT DISTINCT origin_country
FROM trade_transactions
ORDER BY origin_country;

SELECT hscode, MAX(updated_date) AS latest_updated_date
FROM tariff_codes
GROUP BY hscode;

SELECT hscode
FROM trade_transactions
ORDER BY hscode, entity_id;

SELECT description
FROM commodities
WHERE hscode = '1234567890';
